import{_ as e,o,c as i,a0 as r}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"Refatoracao: Memoria Operacional e Transferencia Semantica","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/REFATORACAO_MEMORIA_OPERACIONAL.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/REFATORACAO_MEMORIA_OPERACIONAL.md","lastUpdated":1782593311000}'),l={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/REFATORACAO_MEMORIA_OPERACIONAL.md"};function t(c,a,n,s,d,m){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="refatoracao-memoria-operacional-e-transferencia-semantica" tabindex="-1">Refatoracao: Memoria Operacional e Transferencia Semantica <a class="header-anchor" href="#refatoracao-memoria-operacional-e-transferencia-semantica" aria-label="Permalink to &quot;Refatoracao: Memoria Operacional e Transferencia Semantica&quot;">​</a></h1><p><strong>Status:</strong> Em execucao<br><strong>Data:</strong> 2026-03-18</p><h2 id="objetivo" tabindex="-1">Objetivo <a class="header-anchor" href="#objetivo" aria-label="Permalink to &quot;Objetivo&quot;">​</a></h2><p>Reposicionar o NEXUS de um retriever topologico focado em chunks para um sistema de memoria externa operacional capaz de:</p><ol><li>Recuperar casos antigos relevantes, inclusive sem codigo.</li><li>Relacionar codigo com conceitos abstratos e decisoes anteriores.</li><li>Sustentar continuidade cognitiva acima da janela de contexto nativa da LLM.</li><li>Favorecer transferencia de solucao entre contextos e codebases diferentes.</li></ol><h2 id="restricao-epistemica" tabindex="-1">Restricao epistemica <a class="header-anchor" href="#restricao-epistemica" aria-label="Permalink to &quot;Restricao epistemica&quot;">​</a></h2><ul><li>O sistema nao deve depender de uma ontologia manual do que &quot;merece&quot; virar conhecimento.</li><li>A ingestao continua ampla: codigo, notas, markdowns, decisoes, rascunhos e historico.</li><li>Camadas derivadas (L1/L2/T4+) servem para navegacao, reidratacao e compressao de contexto, nao para policiar o corpus.</li></ul><h2 id="decisoes-de-refatoracao" tabindex="-1">Decisoes de refatoracao <a class="header-anchor" href="#decisoes-de-refatoracao" aria-label="Permalink to &quot;Decisoes de refatoracao&quot;">​</a></h2><ul><li>Nao suportar clientes legados no contrato de query.</li><li>Assumir reingestao total como mecanismo normal quando geometria, topologia ou schema de memoria mudarem.</li><li>Preferir simplicidade operacional e reprodutibilidade a migracoes incrementais complexas.</li><li>Tratar o T4 atual como runtime intermediario, nao como formulacao final da memoria semantica.</li><li>Evoluir a navegacao para uma camada supra-index: acima do relacional e do vetorial, mas alimentada por ambos.</li></ul><h2 id="requisitos-de-produto" tabindex="-1">Requisitos de produto <a class="header-anchor" href="#requisitos-de-produto" aria-label="Permalink to &quot;Requisitos de produto&quot;">​</a></h2><h3 id="r1-memoria-de-casos" tabindex="-1">R1. Memoria de casos <a class="header-anchor" href="#r1-memoria-de-casos" aria-label="Permalink to &quot;R1. Memoria de casos&quot;">​</a></h3><ul><li>Encontrar solucoes antigas, decisoes e fragmentos analogos.</li><li>Preservar contexto temporal e versoes sem depender de releitura global.</li></ul><h3 id="r2-memoria-de-navegacao-semantica" tabindex="-1">R2. Memoria de navegacao semantica <a class="header-anchor" href="#r2-memoria-de-navegacao-semantica" aria-label="Permalink to &quot;R2. Memoria de navegacao semantica&quot;">​</a></h3><ul><li>Representar mais do que chunks brutos sem impor tipologias rigidas ao corpus.</li><li>Permitir que trajetorias, vizinhancas, recorrencias e versoes emerjam como contexto util.</li></ul><h3 id="r3-memoria-de-trabalho-persistente" tabindex="-1">R3. Memoria de trabalho persistente <a class="header-anchor" href="#r3-memoria-de-trabalho-persistente" aria-label="Permalink to &quot;R3. Memoria de trabalho persistente&quot;">​</a></h3><ul><li>Permitir composicao longa: artigo, especificacao, pesquisa, investigacao.</li><li>Reidratar objetivo global, estado atual e proximos passos em cada turno.</li></ul><h3 id="r4-memoria-composicional" tabindex="-1">R4. Memoria composicional <a class="header-anchor" href="#r4-memoria-composicional" aria-label="Permalink to &quot;R4. Memoria composicional&quot;">​</a></h3><ul><li>Retornar &quot;context packs&quot; coerentes em vez de apenas top-k flat.</li><li>Equilibrar profundidade local com diversidade entre fontes.</li></ul><h3 id="r5-avaliacao-de-transferencia" tabindex="-1">R5. Avaliacao de transferencia <a class="header-anchor" href="#r5-avaliacao-de-transferencia" aria-label="Permalink to &quot;R5. Avaliacao de transferencia&quot;">​</a></h3><ul><li>Medir se o sistema ajuda a aplicar principios em contexto novo.</li><li>Nao apenas se recupera o arquivo exato do proprio corpus.</li></ul><h2 id="o-que-manter" tabindex="-1">O que manter <a class="header-anchor" href="#o-que-manter" aria-label="Permalink to &quot;O que manter&quot;">​</a></h2><ul><li>Ingestao versionada em T2.</li><li>Busca vetorial em Qdrant como ponto de entrada.</li><li>Filtros temporais e de dominio no relacional.</li><li>AST e niveis L1/L2 como direcao de enriquecimento semantico nao prescritivo.</li></ul><h2 id="o-que-congelar" tabindex="-1">O que congelar <a class="header-anchor" href="#o-que-congelar" aria-label="Permalink to &quot;O que congelar&quot;">​</a></h2><ul><li>Expansao teorica adicional sobre Hamiltoniano/tensores sem acoplamento ao runtime.</li><li>Novos tipos de edge no Postgres antes de consolidar evals de memoria e transferencia.</li><li>Qualquer tentativa de definir manualmente uma taxonomia fixa de &quot;unidades de conhecimento&quot;.</li></ul><h2 id="o-que-acrescentar" tabindex="-1">O que acrescentar <a class="header-anchor" href="#o-que-acrescentar" aria-label="Permalink to &quot;O que acrescentar&quot;">​</a></h2><h3 id="runtime" tabindex="-1">Runtime <a class="header-anchor" href="#runtime" aria-label="Permalink to &quot;Runtime&quot;">​</a></h3><ul><li><code>/query</code> com resposta HTTP sempre estruturada.</li><li><code>response_mode = packs</code> como default para janelas coerentes por blob.</li><li>Diversidade por <code>fs_path</code> para evitar monopolio de um unico arquivo.</li><li>Recuperacao de contexto vizinho por <code>chunk_index</code>.</li></ul><h3 id="representacao" tabindex="-1">Representacao <a class="header-anchor" href="#representacao" aria-label="Permalink to &quot;Representacao&quot;">​</a></h3><ul><li>Sinais derivados de navegacao: vizinhanca local, recorrencia, continuidade temporal, diversidade de fonte e proximidade estrutural.</li><li>Memoria de trabalho persistente para outlines, secoes, decisoes e pendencias.</li></ul><h3 id="navegacao" tabindex="-1">Navegacao <a class="header-anchor" href="#navegacao" aria-label="Permalink to &quot;Navegacao&quot;">​</a></h3><ul><li>Fazer o T4 evoluir de PPR relacional para camada de navegacao semantica supra-index.</li><li>O vetorial continua como detector de proximidade local.</li><li>O relacional continua como ancora canonica, temporal e versionada.</li><li>A camada superior decide como caminhar e paginar contexto sem depender exclusivamente de nenhum dos dois.</li></ul><h3 id="avaliacao" tabindex="-1">Avaliacao <a class="header-anchor" href="#avaliacao" aria-label="Permalink to &quot;Avaliacao&quot;">​</a></h3><ul><li>Suite de &quot;memory eval&quot; com cinco familias: <ol><li>code_to_concept</li><li>concept_to_code</li><li>old_solution_recall</li><li>cross_codebase_transfer</li><li>long_form_continuity</li></ol></li></ul><h2 id="o-que-otimizar" tabindex="-1">O que otimizar <a class="header-anchor" href="#o-que-otimizar" aria-label="Permalink to &quot;O que otimizar&quot;">​</a></h2><ol><li>Menos dependencia de <code>top_k</code> flat.</li><li>Menos acoplamento do ranking ao Postgres como motor principal de navegacao.</li><li>Mais coerencia de contexto por resposta.</li><li>Melhor relacao entre recall e diversidade.</li><li>Menos modelagem manual de semantica e mais inferencia de trajetoria/contexto.</li></ol><h2 id="fases" tabindex="-1">Fases <a class="header-anchor" href="#fases" aria-label="Permalink to &quot;Fases&quot;">​</a></h2><h3 id="fase-1-sanity-pass" tabindex="-1">Fase 1: Sanity Pass <a class="header-anchor" href="#fase-1-sanity-pass" aria-label="Permalink to &quot;Fase 1: Sanity Pass&quot;">​</a></h3><ul><li>Alinhar runtime, benchmark e documentacao.</li><li>Introduzir context packs.</li><li>Criar matriz de avaliacao.</li><li>Remover dependencia de formatos legados de resposta.</li><li>Formalizar reingestao full-scan como procedimento suportado.</li></ul><h2 id="o-que-testar-agora" tabindex="-1">O que testar agora <a class="header-anchor" href="#o-que-testar-agora" aria-label="Permalink to &quot;O que testar agora&quot;">​</a></h2><ol><li>Contrato de query: <ul><li><code>/query</code> sempre retorna objeto JSON com <code>ok</code>, <code>mode</code>, <code>results</code> e <code>packs</code>.</li><li><code>response_mode = chunks</code> retorna ranking flat em <code>results</code>.</li><li>default sem <code>response_mode</code> retorna <code>mode = packs</code>.</li></ul></li><li>Coerencia de context pack: <ul><li>seed correta em <code>center_abs_id</code>.</li><li>span respeita <code>context_radius</code>.</li><li>chunks ordenados por <code>chunk_index</code>.</li></ul></li><li>Diversidade: <ul><li><code>max_chunks_per_path</code> evita monopolio de um unico arquivo.</li></ul></li><li>Avaliacao funcional: <ul><li>benchmark causal continua rodando em <code>chunks</code>.</li><li>memory eval roda em <code>packs</code>.</li></ul></li><li>Evolucao operacional: <ul><li>reingestao full-scan recompõe o estado sem depender de legado local.</li></ul></li></ol><h3 id="fase-2-memory-semantics" tabindex="-1">Fase 2: Memory Semantics <a class="header-anchor" href="#fase-2-memory-semantics" aria-label="Permalink to &quot;Fase 2: Memory Semantics&quot;">​</a></h3><ul><li>L1/L2 passando a influenciar navegacao e reidratacao, sem filtrar o corpus por dogma.</li><li>T4 deixando de ser apenas PPR em links persistidos e se aproximando de uma camada de caminhada semantica.</li></ul><h3 id="fase-3-transfer" tabindex="-1">Fase 3: Transfer <a class="header-anchor" href="#fase-3-transfer" aria-label="Permalink to &quot;Fase 3: Transfer&quot;">​</a></h3><ul><li>Evals de aplicacao de padrao em base diferente.</li><li>Reuso de regularidade semantica em vez de apenas reuso literal de trecho.</li></ul><h3 id="fase-4-operational-memory" tabindex="-1">Fase 4: Operational Memory <a class="header-anchor" href="#fase-4-operational-memory" aria-label="Permalink to &quot;Fase 4: Operational Memory&quot;">​</a></h3><ul><li>Estado de trabalho persistente para escrita e raciocinio longos.</li><li>Reidratacao deterministica de objetivo + outline + contexto local.</li></ul>',46)])])}const h=e(l,[["render",t]]);export{p as __pageData,h as default};
